public static Location findSafeLocation(Location origin) {
    if (isSafe(origin)) return origin;

    Location worldOrigin = origin.clone();
    // Grid search in 3x3x3
    for (int dx = -1; dx <= 1; dx++) {
        for (int dy = -1; dy <= 1; dy++) {
            for (int dz = -1; dz <= 1; dz++) {
